import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParsePathTest {

    private Path mockPath;
    private Charset charset;
    private CSVFormat format;
    private BufferedReader mockReader;

    @BeforeEach
    void setUp() throws IOException {
        mockPath = mock(Path.class);
        charset = Charset.defaultCharset();
        format = mock(CSVFormat.class);
        mockReader = mock(BufferedReader.class);
    }

    @Test
    void parse_nullPath_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((Path) null, charset, format));
        assertEquals("path", ex.getMessage());
    }

    @Test
    void parse_nullFormat_throwsNullPointerException() {
        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(mockPath, charset, null));
        assertEquals("format", ex.getMessage());
    }

    @Test
    void parse_callsFilesNewBufferedReaderAndDelegates() throws IOException {
        try (MockedStatic<Files> filesMocked = Mockito.mockStatic(Files.class);
             MockedStatic<CSVParser> parserMocked = Mockito.mockStatic(CSVParser.class)) {

            filesMocked.when(() -> Files.newBufferedReader(mockPath, charset)).thenReturn(mockReader);
            CSVParser expectedParser = mock(CSVParser.class);
            parserMocked.when(() -> CSVParser.parse(mockReader, format)).thenReturn(expectedParser);

            CSVParser actualParser = CSVParser.parse(mockPath, charset, format);

            filesMocked.verify(() -> Files.newBufferedReader(mockPath, charset));
            parserMocked.verify(() -> CSVParser.parse(mockReader, format));
            assertSame(expectedParser, actualParser);
        }
    }
}
